import { useRef, useState } from 'react'
import { useParams } from 'react-router-dom'
import html2canvas from 'html2canvas'
import printProducts from '../data/printProducts'

export default function ProductCustomizer() {

  const mockupRef = useRef(null)

  /*
    =========================
    DEV MODE
    =========================
  */

  const DEV_MODE = true

  /*
    =========================
    PIXELS PER INCH
    =========================
  */

  const PIXELS_PER_INCH = 20

  const { id } = useParams()

  const product =
    printProducts.find(
      item => item.id === id
    )

  /*
    =========================
    FRONT LOCKED
    =========================
  */

  const FRONT_PRESET = {

    x: 50.25,
    y: 41.5,

    widthInches: 11.5,
    heightInches: 11.5,

    zoom: 100
  }

  /*
    =========================
    LEFT CHEST LOCKED
    =========================
  */

  const LEFT_CHEST_PRESET = {

    x: 58.15,
    y: 28.9,

    widthInches: 3.5,
    heightInches: 3.25,

    zoom: 100
  }

  /*
    =========================
    BACK LOCKED
    =========================
  */

  const BACK_PRESET = {

    x: 50.25,
    y: 41.5,

    widthInches: 11.5,
    heightInches: 11.5,

    zoom: 100
  }

  /*
    =========================
    TRUE LOCKED PRESETS
    =========================
  */

  const presetMap = {

    front:
      FRONT_PRESET,

    'left-chest':
      LEFT_CHEST_PRESET,

    back:
      BACK_PRESET
  }

  const [selectedColor, setSelectedColor] =
    useState(
      product.colors[0]
    )

  const [uploadedLogo, setUploadedLogo] =
    useState(null)

  const [activePreset, setActivePreset] =
    useState('front')

  const [logoScale, setLogoScale] =
    useState(100)

  const currentPreset =
    presetMap[activePreset]

  const currentPosition = {

    x: currentPreset.x,
    y: currentPreset.y
  }

  /*
    =========================
    INCHES TO PIXELS
    =========================
  */

  const currentWidthPx =
    currentPreset.widthInches *
    PIXELS_PER_INCH

  const currentHeightPx =
    currentPreset.heightInches *
    PIXELS_PER_INCH

  /*
    =========================
    UPLOAD
    =========================
  */

  const handleUpload = (e) => {

    const file =
      e.target.files[0]

    if (!file) return

    const imageUrl =
      URL.createObjectURL(file)

    setUploadedLogo(
      imageUrl
    )
  }

  /*
    =========================
    PRESET SWITCH
    =========================
  */

  const setPreset = (type) => {

    setActivePreset(type)

    const preset =
      presetMap[type]

    setLogoScale(
      preset.zoom
    )
  }

  /*
    =========================
    REMOVE LOGO
    =========================
  */

  const removeLogo = () => {

    setUploadedLogo(null)
  }

  /*
    =========================
    EXPORT
    =========================
  */

  const exportMockup = async () => {

    const canvas =
      await html2canvas(
        mockupRef.current,
        {
          backgroundColor: null,
          scale: 3,
          useCORS: true
        }
      )

    const image =
      canvas.toDataURL(
        'image/png'
      )

    const link =
      document.createElement(
        'a'
      )

    link.href = image

    link.download =
      `mockup-${activePreset}.png`

    link.click()
  }

  return (

    <div className="h-screen bg-black text-white overflow-hidden">

      <div className="grid grid-cols-1 xl:grid-cols-[65%_35%] h-full">

        {/* MOCKUP */}

        <div
          ref={mockupRef}
          className="bg-[#e9e9e9] flex items-center justify-center relative p-10 w-full h-full overflow-hidden"
        >

          <img
            src={
              activePreset === 'back'
                ? selectedColor.backImage
                : selectedColor.image
            }
            alt="product"
            className="w-full max-w-[700px] max-h-[88vh] object-contain"
          />

          {/* PRINT AREA */}

          <div
            className="absolute flex items-start justify-center"
            style={{

              width:
                `${currentWidthPx}px`,

              height:
                `${currentHeightPx}px`,

              top:
                `${currentPosition.y}%`,

              left:
                `${currentPosition.x}%`,

              transform:
                'translate(-50%, -50%)',

              overflow: 'hidden',

              border:
                DEV_MODE
                  ? '2px solid #ff2b2b'
                  : 'none'
            }}
          >

            {uploadedLogo && (

              <img
                src={uploadedLogo}
                alt="logo"
                className="select-none pointer-events-none"
                style={{

                  width: '100%',

                  height: 'auto',

                  maxHeight: '100%',

                  objectFit: 'contain',

                  transform:
                    `scale(${logoScale / 100})`,

                  transformOrigin:
                    'top center'
                }}
                draggable={false}
              />

            )}

          </div>

        </div>

        {/* RIGHT PANEL */}

        <div className="bg-black border-l border-[#1d1d1d] flex flex-col h-full overflow-y-auto">

          {/* HEADER */}

          <div className="border-b border-[#1d1d1d] p-6">

            <p className="text-yellow-500 text-[10px] tracking-[0.3em] uppercase mb-2">
              Inspired By God
            </p>

            <h1 className="text-4xl font-black">
              {product.name}
            </h1>

          </div>

          {/* CONTROLS */}

          <div className="p-6 space-y-6">

            {/* COLORS */}

            <div>

              <h2 className="text-sm font-black mb-4">
                Shirt Colors
              </h2>

              <div className="grid grid-cols-2 gap-3">

                {product.colors.map(
                  (color) => (

                    <button
                      key={color.name}
                      onClick={() =>
                        setSelectedColor(color)
                      }
                      className={`p-4 rounded-xl text-xs font-black capitalize ${
                        selectedColor.name ===
                        color.name
                          ? 'bg-yellow-500 text-black'
                          : 'bg-[#111] border border-[#222]'
                      }`}
                    >
                      {color.name}
                    </button>

                  )
                )}

              </div>

            </div>

            {/* PLACEMENT */}

            <div>

              <h2 className="text-sm font-black mb-4">
                Placement
              </h2>

              <div className="grid grid-cols-1 gap-3">

                {[
                  'front',
                  'left-chest',
                  'back'
                ].map((item) => (

                  <button
                    key={item}
                    onClick={() =>
                      setPreset(item)
                    }
                    className={`p-4 rounded-xl text-xs font-black ${
                      activePreset === item
                        ? 'bg-yellow-500 text-black'
                        : 'bg-[#111] border border-[#222]'
                    }`}
                  >
                    {item}
                  </button>

                ))}

              </div>

            </div>

            {/* UPLOAD */}

            <div>

              <h2 className="text-sm font-black mb-4">
                Upload Logo
              </h2>

              <input
                type="file"
                accept="image/png,image/jpeg"
                onChange={handleUpload}
                className="w-full bg-[#111] border border-[#222] rounded-xl p-4 text-sm"
              />

            </div>

            {/* ACTIONS */}

            {uploadedLogo && (

              <>

                <button
                  onClick={removeLogo}
                  className="w-full border border-red-500 text-red-500 py-4 rounded-xl text-xs font-black"
                >
                  REMOVE LOGO
                </button>

                <button
                  onClick={exportMockup}
                  className="w-full bg-white text-black py-4 rounded-xl text-xs font-black"
                >
                  EXPORT MOCKUP
                </button>

                {/* ZOOM */}

                <div>

                  <div className="flex justify-between mb-3">

                    <p className="text-xs text-white/60">
                      Zoom
                    </p>

                    <p className="text-xs text-yellow-500 font-black">
                      {logoScale}%
                    </p>

                  </div>

                  <input
                    type="range"
                    min="50"
                    max="180"
                    value={logoScale}
                    onChange={(e) =>
                      setLogoScale(
                        e.target.value
                      )
                    }
                    className="w-full"
                  />

                </div>

              </>

            )}

          </div>

        </div>

      </div>

    </div>

  )
}
